package kotlinx.coroutines.exceptions

import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.coroutineScope
import kotlinx.coroutines.runBlocking
import kotlinx.coroutines.runTest
import kotlin.test.assertEquals
import kotlin.test.assertTrue
import kotlin.test.fail
import org.junit.Test

class StackTraceRecoveryConstructorSelectionTest : TestBase() {

    private class NestedException : RuntimeException {
        constructor(message: String) : super(message)
        constructor(cause: Throwable) : super(cause)
        constructor() : super()
    }

    @Test
    fun testPreferCauseConstructorToAvoidNestedCopies() = runTest {
        val result = runCatching {
            coroutineScope<Unit> {
                throw NestedException(IllegalStateException("ERROR"))
            }
        }
        val exception = result.exceptionOrNull() ?: fail("Expected coroutine scope to fail")
        assertTrue(exception is NestedException)
        val cause = exception.cause ?: fail("Expected cause to be present")
        assertTrue(cause is IllegalStateException)
        assertEquals("ERROR", cause.message)
    }
}
"}

